using NP std;
NP phigrOS
{
	il ll read()
	{
		ll x = 0, f = 1;
		char ch = gc();
		wh(ch < '0' || ch > '9')
		{
			if (ch == '-')f = -1;
			ch = getchar();
		}
		wh(ch >= '0' && ch <= '9')
		{
			x = x * 10 + ch - '0';
			ch = gc();
		}
		return x * f;
	}
	void write(ll x)
	{
		if (x < 0)pc('-'), x = -x;
		if (x > 9)write(x / 10);
		pc(x % 10 + '0');
	}
	void writeln(ll x)
	{
		write(x);
		puts("");
		return;
	}
}
using NP phigrOS;
int n, R;
signed main(void)
{
	cin >> n >> R;
	int x = n;
	if (n == 0)
	{
		cout << x << "=0(base" << R << ")";
		return 0;
	}
	string res;
	while (n != 0)
	{
		int rem = n % R;
		n /= R;
		if (rem < 0)
		{
			rem -= R;
			n += 1;
		}
		res.push_back(rem < 10 ? '0' + rem : 'A' + rem - 10);
	}
	reverse(res.begin(), res.end());
	cout << x << "=" << res << "(base" << R << ")" ;
	return false;
}
